import{_ as r,o as a,c as t,ag as o}from"./chunks/framework.9L5wI8-n.js";const m=JSON.parse('{"title":"AI Image Renamer","description":"","frontmatter":{},"headers":[],"relativePath":"introduction/index.md","filePath":"introduction/index.md"}'),s={name:"introduction/index.md"};function i(n,e,l,d,g,p){return a(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="ai-image-renamer" tabindex="-1">AI Image Renamer <a class="header-anchor" href="#ai-image-renamer" aria-label="Permalink to &quot;AI Image Renamer&quot;">​</a></h1><p><a href="https://wordpress.org/plugins/ai-image-renamer/" target="_blank" rel="noreferrer"><img src="https://img.shields.io/wordpress/plugin/v/ai-image-renamer?style=flat-square&amp;logo=wordpress&amp;label=Version" alt="WordPress Plugin Version"></a><a href="https://wordpress.org/plugins/ai-image-renamer/" target="_blank" rel="noreferrer"><img src="https://img.shields.io/wordpress/plugin/dt/ai-image-renamer?style=flat-square&amp;logo=wordpress&amp;label=Downloads" alt="WordPress Plugin Downloads"></a><a href="https://wordpress.org/support/plugin/ai-image-renamer/reviews/" target="_blank" rel="noreferrer"><img src="https://img.shields.io/wordpress/plugin/stars/ai-image-renamer?style=flat-square&amp;logo=wordpress&amp;label=Rating" alt="WordPress Plugin Rating"></a><a href="https://wordpress.org/plugins/ai-image-renamer/" target="_blank" rel="noreferrer"><img src="https://img.shields.io/wordpress/plugin/required-php/ai-image-renamer?style=flat-square&amp;logo=php&amp;label=PHP" alt="WordPress Plugin Required PHP"></a><a href="https://wordpress.org/plugins/ai-image-renamer/" target="_blank" rel="noreferrer"><img src="https://img.shields.io/wordpress/plugin/tested/ai-image-renamer?style=flat-square&amp;logo=wordpress&amp;label=Tested%20up%20to" alt="WordPress Plugin Tested WP Version"></a><a href="https://www.gnu.org/licenses/gpl-2.0.html" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/License-GPL--2.0--or--later-blue?style=flat-square" alt="License"></a></p><p><strong>AI Image Renamer</strong> transforms your WordPress media management by automatically generating SEO-friendly, descriptive filenames for uploaded images using Groq&#39;s powerful Vision API. Say goodbye to <code>IMG_1234.jpg</code> and hello to <code>golden-retriever-playing-park.jpg</code> — all without any manual effort.</p><p>The plugin intercepts every image upload via the WordPress Media Library, sends it to Groq&#39;s Vision API for analysis, and renames the file with descriptive, keyword-rich slugs before it is saved. Optionally, it also populates the image&#39;s <code>alt</code> attribute with the AI-generated description — improving both SEO and accessibility in a single step.</p><h2 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h2><p>AI Image Renamer is built around a few core principles: automation, security, and extensibility.</p><ul><li>🤖 <strong>AI-Powered Naming</strong> — Uses Llama 4 vision models (Maverick for detail, Scout for speed) to understand image content and generate meaningful filenames.</li><li>🔍 <strong>SEO-Optimized</strong> — Produces keyword-rich, lowercase, hyphenated slugs that search engines love.</li><li>🔒 <strong>Secure by Default</strong> — API keys are encrypted at rest using <code>defuse/php-encryption</code>. For maximum security, the encryption key can be defined in <code>wp-config.php</code>.</li><li>🎯 <strong>Smart Alt Text</strong> — When enabled, the AI description is also saved as the image&#39;s <code>alt</code> attribute, helping with accessibility compliance.</li><li>⚙️ <strong>Fully Configurable</strong> — Choose which image types to process, how many keywords to generate, and which AI model to use — all from a modern admin interface.</li><li>🛡️ <strong>Graceful Fallback</strong> — If the API is unreachable or returns an error, the original filename is preserved. Uploads never fail because of the plugin.</li><li>🚀 <strong>Free to Use</strong> — Powered by Groq&#39;s generous free-tier API. No credit card required.</li></ul><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>When you upload an image, the plugin hooks into WordPress&#39;s <code>wp_handle_upload_prefilter</code> filter. The image is base64-encoded and sent to Groq&#39;s Vision API along with a configurable prompt. The API returns descriptive keywords, which are sanitized into an SEO-friendly slug and applied as the new filename. If alt text generation is enabled, the description is stored via a WordPress transient and applied once the attachment is created.</p><h2 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Before</th><th>After</th></tr></thead><tbody><tr><td><code>IMG_1234.jpg</code></td><td><code>golden-retriever-playing-fetch-sunny-park.jpg</code></td></tr><tr><td><code>photo_2026.png</code></td><td><code>modern-office-desk-laptop-coffee.png</code></td></tr><tr><td><code>screenshot.webp</code></td><td><code>wordpress-dashboard-settings-page.webp</code></td></tr></tbody></table><h2 id="supported-formats" tabindex="-1">Supported Formats <a class="header-anchor" href="#supported-formats" aria-label="Permalink to &quot;Supported Formats&quot;">​</a></h2><p>The plugin processes <strong>JPEG</strong>, <strong>PNG</strong>, <strong>WebP</strong>, <strong>AVIF</strong>, and <strong>GIF</strong> images. You can enable or disable individual formats in the <a href="/wp-ai-image-renamer/usage/settings.html">settings</a>.</p><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><p>You need <strong>WordPress 6.0+</strong>, <strong>PHP 8.2+</strong>, and a free Groq API key from <a href="https://console.groq.com/keys" target="_blank" rel="noreferrer">console.groq.com</a>. Registration takes less than a minute and does not require a credit card.</p><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li><a href="https://github.com/thaikolja/wp-ai-image-renamer" target="_blank" rel="noreferrer">GitHub Repository</a></li><li><a href="https://gitlab.com/thaikolja/wp-ai-image-renamer" target="_blank" rel="noreferrer">GitLab Repository</a></li><li><a href="https://wordpress.org/plugins/ai-image-renamer/" target="_blank" rel="noreferrer">WordPress.org Plugin Page</a></li><li><a href="https://console.groq.com/keys" target="_blank" rel="noreferrer">Groq API Console</a></li></ul><h2 id="license" tabindex="-1">License <a class="header-anchor" href="#license" aria-label="Permalink to &quot;License&quot;">​</a></h2><p>AI Image Renamer is released under the <a href="https://www.gnu.org/licenses/gpl-2.0.html" target="_blank" rel="noreferrer">GPL-2.0-or-later</a> license.</p>',19)])])}const c=r(s,[["render",i]]);export{m as __pageData,c as default};
